mapper.select:
SELECT plan_id, user_id, plan_name, start_date, end_date, plan_content, create_time, update_time, is_public
FROM travel_plans
WHERE plan_id = #{planId}

SELECT plan_id, user_id, plan_name, start_date, end_date, plan_content, create_time, update_time, is_public
FROM travel_plans
WHERE user_id = #{userId}
ORDER BY create_time DESC
LIMIT #{offset}, #{size}

SELECT COUNT(*) 
FROM travel_plans
WHERE user_id = #{userId}

SELECT plan_id, user_id, plan_name, start_date, end_date, plan_content, create_time, update_time, is_public
FROM travel_plans
WHERE is_public = 1

    AND user_id = #{userId}

ORDER BY create_time DESC
LIMIT #{offset}, #{size}
